import {
  activePeriodPermits, activeProfiles, applyDispatch, assignmentSummary, capabilitySummary, comfortableTruckTrips, customerAllowedMaterialIds, customerRuleSummary,
  defaultCustomerMaterialId, defaultState, ensureState, financialSummary, isDispatchable, loadScore, makeOrderFromMaterial,
  makeWhatsAppMessage, materialById, materialLabel, maximumTruckTrips, recordActualTrip, recordQuarryTripLog, renumberAssignments,
  quarryEnquiriesForDate, sandpitPermitPlan,
  sourceById, tallyForDate, tomorrowISO, truckLabel, uid,
} from "./scheduler.js";

const STORAGE_KEY = "dispatch-pilot-state-v9";
const LEGACY_STORAGE_KEYS = ["dispatch-pilot-state-v8", "dispatch-pilot-state-v7", "dispatch-pilot-state-v6", "dispatch-pilot-state-v5", "dispatch-pilot-state-v4", "dispatch-pilot-state-v3", "dispatch-pilot-state-v1"];
const DAILY_TABS = [["trucks", "Trucks"], ["orders", "Orders"], ["tally", "Tally"], ["dispatch", "Dispatch"], ["whatsapp", "WhatsApp"], ["logs", "Trip log"]];
const root = document.querySelector("#app");
const requestedTab = new URLSearchParams(window.location.search).get("tab");
const ui = { tab: [...DAILY_TABS.map(([id]) => id), "settings"].includes(requestedTab) ? requestedTab : "trucks", date: tomorrowISO(), toast: "", toastTone: "", newOrderCustomer: "", openTruck: "", openQuarryLogTruck: "" };
let state = readState();

function readState() { try { const saved = localStorage.getItem(STORAGE_KEY) || LEGACY_STORAGE_KEYS.map((key) => localStorage.getItem(key)).find(Boolean); return ensureState(saved ? JSON.parse(saved) : defaultState()); } catch { return defaultState(); } }
function esc(value) { return String(value ?? "").replace(/[&<>'"]/g, (character) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "'": "&#39;", '"': "&quot;" })[character]); }
function number(value) { return Math.max(0, Number(value) || 0); }
function money(value) { return `RM ${number(value).toFixed(2)}`; }
function activeOrders() { return state.orders.filter((item) => item.date === ui.date); }
function activeAssignments() { return state.assignments.filter((item) => item.date === ui.date).sort((a, b) => `${truck(a.truckId)?.prefix || ""} ${truck(a.truckId)?.number || ""}`.localeCompare(`${truck(b.truckId)?.prefix || ""} ${truck(b.truckId)?.number || ""}`) || a.tripNumber - b.tripNumber); }
function customer(id) { return state.customers.find((item) => item.id === id); }
function truck(id) { return state.trucks.find((item) => item.id === id); }
function dispatchableTrucks() { return state.trucks.filter(isDispatchable); }
function badge(status) { return `<span class="badge ${esc(String(status).toLowerCase().replace(/\s+/g, "-"))}">${esc(status)}</span>`; }

function writeState() { state = { ...state, schemaVersion: 9, updatedAt: new Date().toISOString() }; localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); }
function flashSave(message = "Saved") { const node = document.querySelector("#save-status"); if (!node) return; node.textContent = message; node.classList.add("saving"); window.clearTimeout(window.__dispatchSaved); window.__dispatchSaved = window.setTimeout(() => { const target = document.querySelector("#save-status"); if (target) { target.textContent = "Saved on phone"; target.classList.remove("saving"); } }, 1150); }
function autosave(message = "Saved") { try { writeState(); flashSave(message); } catch { showToast("Phone storage is full — changes could not be saved", "danger"); } }
function showToast(message, tone = "success") { ui.toast = message; ui.toastTone = tone; render(); window.clearTimeout(window.__dispatchToast); window.__dispatchToast = window.setTimeout(() => { ui.toast = ""; render(); }, 2600); }
function persistAndRender(message = "Saved") { try { writeState(); } catch { showToast("Phone storage is full — changes could not be saved", "danger"); return; } showToast(message); }

function prepareDate(date) {
  if (state.orders.some((item) => item.date === date)) return false;
  const priorDate = [...new Set(state.orders.map((item) => item.date).filter((item) => item < date))].sort().at(-1); if (!priorDate) return false;
  const copied = state.orders.filter((item) => item.date === priorDate).map((item) => ({ ...item, id: uid("order"), date, updatedAt: new Date().toISOString() }));
  state = { ...state, orders: [...state.orders, ...copied] }; autosave(`Copied ${copied.length} previous order lines`); return true;
}
prepareDate(ui.date);

function customerOptions(selected = "") { return `<option value="">Choose customer</option>${state.customers.slice().sort((a, b) => a.name.localeCompare(b.name)).map((item) => `<option value="${esc(item.id)}" ${item.id === selected ? "selected" : ""}>${esc(item.name)}</option>`).join("")}`; }
function sourceOptions(selected = "", includeBlank = true) { return `${includeBlank ? `<option value="" ${!selected ? "selected" : ""}>Choose source</option>` : ""}${state.sources.slice().sort((a, b) => a.name.localeCompare(b.name)).map((item) => `<option value="${esc(item.id)}" ${item.id === selected ? "selected" : ""}>${esc(item.name)} (${esc(item.type)})</option>`).join("")}`; }
function periodSourceOptions(selected = "") { const sources = state.sources.filter((source) => source.type === "Sandpit" && source.permitScheme === "Period").sort((left, right) => left.name.localeCompare(right.name)); return `<option value="">Choose period sandpit</option>${sources.map((source) => `<option value="${esc(source.id)}" ${source.id === selected ? "selected" : ""}>${esc(source.name)}</option>`).join("")}`; }
function truckOptions(selected = "") { return `<option value="">Choose truck</option>${state.trucks.slice().sort((left, right) => truckLabel(left).localeCompare(truckLabel(right))).map((item) => `<option value="${esc(item.id)}" ${item.id === selected ? "selected" : ""}>${esc(truckLabel(item))}</option>`).join("")}`; }
function sourceMultiOptions(materialName, selectedIds = []) { const sources = state.sources.filter((source) => state.materials.some((material) => material.sourceId === source.id && material.name.trim().toLowerCase() === String(materialName || "").trim().toLowerCase())); return sources.map((source) => `<option value="${esc(source.id)}" ${selectedIds.includes(source.id) ? "selected" : ""}>${esc(source.name)}</option>`).join("") || "<option disabled>No saved source provides this material yet</option>"; }
function materialNameOptions(selected = "", kind = "") { const names = [...new Set(state.materials.filter((item) => !kind || item.kind === kind).map((item) => item.name))].sort((a, b) => a.localeCompare(b)); return `<option value="">Choose material</option>${names.map((name) => `<option value="${esc(name)}" ${name === selected ? "selected" : ""}>${esc(name)}</option>`).join("")}`; }
function materialOptions(selected = "", customerId = "", kind = "") { const target = customer(customerId); const accepted = target ? new Set(customerAllowedMaterialIds(state, target)) : null; const options = state.materials.filter((item) => (!kind || item.kind === kind) && (!accepted || accepted.has(item.id))).sort((a, b) => materialLabel(state, a.id).localeCompare(materialLabel(state, b.id))); return `<option value="">Choose material and source</option>${options.map((item) => `<option value="${esc(item.id)}" ${item.id === selected ? "selected" : ""}>${esc(materialLabel(state, item.id))}</option>`).join("")}`; }
function overrideOptions(order) { const target = customer(order.customerId); const defaultId = defaultCustomerMaterialId(state, target); const allowed = customerAllowedMaterialIds(state, target); const overriding = order.materialOverride ?? (order.materialId && order.materialId !== defaultId); return `<option value="__default__" ${!overriding ? "selected" : ""}>Use saved setting (${esc(materialLabel(state, defaultId))})</option>${allowed.map((id) => `<option value="${esc(id)}" ${overriding && id === order.materialId ? "selected" : ""}>Special: ${esc(materialLabel(state, id))}</option>`).join("")}`; }
function zoneOptions(selected) { return ["Near", "Far", "Stone"].map((item) => `<option value="${item}" ${item === selected ? "selected" : ""}>${item}</option>`).join(""); }
function statusOptions(selected) { return ["Available", "Quarry Only", "Off", "Breakdown", "Scheduled Repair"].map((item) => `<option ${item === selected ? "selected" : ""}>${item}</option>`).join(""); }
function stepper(entity, id, field, value, extra = "") { return `<div class="stepper"><button type="button" data-action="step-value" data-entity="${entity}" data-id="${esc(id)}" data-field="${field}" data-delta="-1" aria-label="Reduce">−</button><input type="number" min="0" inputmode="numeric" value="${esc(number(value))}" data-${entity}-field="${field}" ${extra}><button type="button" data-action="step-value" data-entity="${entity}" data-id="${esc(id)}" data-field="${field}" data-delta="1" aria-label="Increase">+</button></div>`; }
function refreshCustomerMaterialIds(nextState = state) { return { ...nextState, customers: nextState.customers.map((item) => ({ ...item, materialIds: customerAllowedMaterialIds(nextState, item) })) }; }
function orderTotals() { return ["Near", "Far", "Stone"].map((zone) => ({ zone, count: activeOrders().filter((item) => item.zone === zone).reduce((sum, item) => sum + number(item.loads), 0) })); }
function fleetTotals() { const totals = { Daily: 0, Near: 0, Far: 0, Stone: 0 }; dispatchableTrucks().forEach((item) => { totals.Daily += maximumTruckTrips(item); const profiles = activeProfiles(item); if (String(item.status).toLowerCase() !== "quarry only") { totals.Near += Math.max(0, ...profiles.map((profile) => number(profile.near))); totals.Far += Math.max(0, ...profiles.map((profile) => number(profile.far))); } totals.Stone += Math.max(0, ...profiles.map((profile) => number(profile.stone))); }); return totals; }
function tripColumns() { return Math.max(5, ...state.trucks.map((item) => maximumTruckTrips(item)), ...state.trucks.map((item) => activeAssignments().filter((assignment) => assignment.truckId === item.id).length)); }

function layout(content) { return `<header class="topbar"><div><p class="eyebrow">DISPATCH PILOT</p><h1>${esc(state.companyName || "My Transport Dispatch")}</h1></div><div class="header-actions"><span id="save-status">Saved on phone</span><button class="icon-button" data-action="go-settings">Settings</button></div></header><main><section class="date-strip"><label>Dispatch date<input id="dispatch-date" type="date" value="${esc(ui.date)}"></label><span>${activeAssignments().length ? `${activeAssignments().length} trips planned` : "Plan not generated"}</span></section>${content}</main><nav class="bottom-nav daily-nav">${DAILY_TABS.map(([id, label]) => `<button class="${ui.tab === id ? "active" : ""}" data-tab="${id}"><b>${label.slice(0, 1)}</b><span>${label}</span></button>`).join("")}</nav>${ui.toast ? `<div class="toast ${esc(ui.toastTone)}">${esc(ui.toast)}</div>` : ""}`; }

function capabilityEditor(item) {
  const profiles = item.capabilities || [];
  return `<details class="capability-editor" ${ui.openTruck === item.id ? "open" : ""}><summary><b>Route plans</b><span>${esc(capabilitySummary(item))}</span></summary><p class="field-hint">Each line is one valid full-day route combination. For example: 5 Near, 3 Near + 1 Far, 4 Near + 1 Stone, or 3 Near + 1 Far + 1 Stone.</p><div class="capability-list">${profiles.map((profile) => `<div data-capability="${esc(profile.id)}"><span>Plan</span>${stepper("capability", `${item.id}|${profile.id}`, "near", profile.near)}<small>Near</small>${stepper("capability", `${item.id}|${profile.id}`, "far", profile.far)}<small>Far</small>${stepper("capability", `${item.id}|${profile.id}`, "stone", profile.stone)}<small>Stone</small><button class="delete" data-action="delete-capability" data-truck="${esc(item.id)}" data-capability="${esc(profile.id)}">Remove</button></div>`).join("")}</div><button class="secondary" data-action="add-capability" data-id="${esc(item.id)}">Add route plan</button></details>`;
}
function repairEditor(item) { const repair = item.repairCapacity || {}; return `<div class="repair-config"><b>Scheduled repair settings</b><div class="repair-grid"><label>Repair time<select data-repair-field="repairTime"><option ${item.repairTime === "Morning" ? "selected" : ""}>Morning</option><option ${item.repairTime === "Afternoon" ? "selected" : ""}>Afternoon</option></select></label><label class="inline-check"><input type="checkbox" data-repair-field="earlyRepair" ${item.earlyRepair ? "checked" : ""}> No early urgent jobs</label><label>Near${stepper("repair", item.id, "near", repair.near)}</label><label>Far${stepper("repair", item.id, "far", repair.far)}</label><label>Stone${stepper("repair", item.id, "stone", repair.stone)}</label></div><small>The repair capacity is used only while this truck is marked Scheduled Repair.</small></div>`; }
function trucksPage() {
  const totals = fleetTotals();
  return `<section class="page-title"><p class="eyebrow">STEP 1 — DAILY FLEET</p><h2>Availability and truck capability</h2><p>Changes save automatically. Maximum loads come from saved route combinations, not from a separate Daily number.</p></section><section class="mini-summary"><span><b>${dispatchableTrucks().length}</b> working trucks</span><span><b>${totals.Daily}</b> possible loads</span><span><b>${totals.Near}/${totals.Far}/${totals.Stone}</b> maximum N / F / S</span></section><section class="panel compact-panel"><div class="section-head"><div><h2>Tomorrow’s fleet</h2><small>Status, reason and maximum loads are under the frozen truck plate. Open Route plans only when a truck’s capability changes.</small></div></div><div class="table-scroll"><table class="compact-table fleet-table"><thead><tr><th class="sticky-col">Truck</th><th>Route plans and fairness</th></tr></thead><tbody>${state.trucks.map((item) => { const score = loadScore(state, item.id, ui.date); return `<tr data-truck="${esc(item.id)}" data-status="${esc(item.status.toLowerCase())}"><td class="sticky-col truck-cell"><b class="truck-name">${esc(truckLabel(item))}</b><select data-truck-field="status">${statusOptions(item.status)}</select><small><b>${maximumTruckTrips(item)}</b> maximum loads</small><label class="status-reason">Reason<input data-truck-field="statusReason" value="${esc(item.statusReason || "")}" placeholder="Off, breakdown, repair or quarry note"></label></td><td class="fleet-plan-cell">${capabilityEditor(item)}${repairEditor(item)}<small class="fairness-line"><b>30-day fairness</b> ${score.historical} loads · ${score.far} Far · ${score.stone} Stone · ${score.quarry} quarry · ${score.planned} planned</small></td></tr>`; }).join("")}</tbody></table></div></section><details class="panel compact-details add-under-list"><summary>Add truck</summary><form class="inline-form" data-form="new-truck"><input name="prefix" placeholder="Prefix"><input required name="number" placeholder="Full registration"><select name="status">${statusOptions("Available")}</select><input name="near" type="number" min="0" value="5" placeholder="Near"><input name="far" type="number" min="0" value="0" placeholder="Far"><input name="stone" type="number" min="0" value="0" placeholder="Stone"><button class="primary" type="submit">Add</button></form><small class="muted">This creates the first route plan. Add the truck’s other valid combinations from its row afterwards.</small></details>`;
}

function orderRow(order) { return `<tr data-order="${esc(order.id)}"><td class="sticky-col"><b>${esc(customer(order.customerId)?.name || "Choose customer")}</b></td><td>${stepper("order", order.id, "loads", order.loads)}</td><td><select data-order-field="zone">${zoneOptions(order.zone)}</select></td><td><label class="inline-check"><input type="checkbox" data-order-field="early" ${order.early ? "checked" : ""}>Early</label></td><td><select data-order-field="materialId">${overrideOptions(order)}</select></td><td><input class="short-note" data-order-field="notes" value="${esc(order.notes)}" placeholder="Remark"></td><td><button class="delete" data-action="delete-order" data-id="${esc(order.id)}">×</button></td></tr>`; }
function ordersPage() { const totals = orderTotals(); const selected = customer(ui.newOrderCustomer); return `<section class="page-title"><p class="eyebrow">STEP 2 — CUSTOMER ORDER</p><h2>Reusable daily order template</h2><p>Yesterday’s order lines are copied automatically for a new date. Change the load with + / −; use Material override only for a special case.</p></section><section class="mini-summary"><span><b>${totals[0].count}</b> Near</span><span><b>${totals[1].count}</b> Far</span><span><b>${totals[2].count}</b> Stone</span><span><b>${totals.reduce((sum, item) => sum + item.count, 0)}</b> total</span></section><section class="panel compact-panel"><div class="section-head"><div><h2>Order lines</h2><small>Every edit is applied immediately to this phone.</small></div></div><div class="table-scroll"><table class="compact-table orders-table"><thead><tr><th class="sticky-col">Customer</th><th>Loads</th><th>Zone</th><th>Early</th><th>Material override only</th><th>Remark</th><th></th></tr></thead><tbody>${activeOrders().map(orderRow).join("") || "<tr><td colspan='7' class='empty-cell'>No orders for this date. Use the previous-date button below.</td></tr>"}</tbody></table></div></section><details class="panel compact-details"><summary>Add another customer order</summary><form class="add-order-form" data-form="new-order"><div class="inline-form"><select required name="customerId" data-new-order-customer>${customerOptions(ui.newOrderCustomer)}</select><input required name="loads" type="number" min="1" value="1"><select name="zone">${zoneOptions(selected?.defaultZone || "Near")}</select><label class="inline-check"><input name="early" type="checkbox">Early</label></div><div class="inline-form"><select name="materialId">${materialOptions("", selected?.id || "", selected?.kind || "")}</select><input name="notes" placeholder="Remark"><button class="primary" type="submit">Add line</button></div><small>Leave Material blank to use the customer’s saved material/source rule.</small></form></details>`; }

function tallyTable() { const tally = tallyForDate(state, ui.date); return `<section class="panel compact-panel tally-panel"><div class="section-head"><div><h2>Customer order vs planned trips</h2><small>Check again after a manual dispatch change.</small></div><span>${tally.every((item) => item.balance === 0) ? badge("Tally") : badge("Review")}</span></div><div class="table-scroll"><table class="compact-table tally-table"><thead><tr><th>Customer</th><th>Need</th><th>Planned</th><th>Balance</th></tr></thead><tbody>${tally.map((item) => `<tr class="${item.balance === 0 ? "ok" : "mismatch"}"><td>${esc(item.customerName)}</td><td>${item.required}</td><td>${item.planned}</td><td><b>${item.balance > 0 ? "+" : ""}${item.balance}</b></td></tr>`).join("") || "<tr><td colspan='4' class='empty-cell'>No order lines to check.</td></tr>"}</tbody></table></div></section>`; }
function tallyPage() { const capacity = fleetTotals(); const demand = Object.fromEntries(orderTotals().map((item) => [item.zone, item.count])); const dailyBalance = capacity.Daily - activeOrders().reduce((sum, item) => sum + number(item.loads), 0); const rows = ["Near", "Far", "Stone"].map((zone) => ({ zone, need: demand[zone], capacity: capacity[zone] })); const unresolved = state.lastAllocation?.date === ui.date ? state.lastAllocation.unresolved || [] : []; const permitWarnings = state.lastAllocation?.date === ui.date ? state.lastAllocation.permitWarnings || [] : []; const permit = sandpitPermitPlan(state, ui.date); const quarryRotation = permit.recommendedQuarryOnlyTruckIds.map((id) => truckLabel(truck(id))).join(" / "); const permitMessage = permit.groupCount ? `Sandpit permit plan: ${permit.groupCount} truck${permit.groupCount === 1 ? "" : "s"} — ${permit.farLoads} × (2 Near + 1 Far) and ${permit.groups.filter((group) => !group.far).length} × 4 Near.` : "No sandpit permit is needed because there are no sandpit orders."; return `<section class="page-title"><p class="eyebrow">STEP 3 — CAPACITY CHECK</p><h2>Demand against today’s fleet capability</h2><p>Near capacity is deliberately flexible: a truck can fill an unused Far or Stone slot with Near work when that is one of its capability plans.</p></section><section class="mini-summary ${dailyBalance < 0 ? "warning-summary" : ""}"><span><b>${activeOrders().reduce((sum, item) => sum + number(item.loads), 0)}</b> customer loads</span><span><b>${capacity.Daily}</b> fleet capacity</span><span><b>${dailyBalance >= 0 ? "+" : ""}${dailyBalance}</b> overall balance</span></section><section class="panel compact-panel permit-panel"><p class="eyebrow">SANDPIT PERMIT RECOMMENDATION</p><b>${esc(permitMessage)}</b><p>${permit.extraNearLoads ? `Add ${permit.extraNearLoads} Near sand load${permit.extraNearLoads === 1 ? "" : "s"} to complete the permit groups (${permit.nearLoads} now → ${permit.targetNearLoads} target).` : `Your ${permit.nearLoads} Near sand loads already fit the permit groups.`}</p><p>${permit.eligibleTruckCount >= permit.groupCount ? `${permit.eligibleTruckCount} trucks can cover the ${permit.groupCount} sandpit permits.` : `Only ${permit.eligibleTruckCount} suitable truck(s) can cover ${permit.groupCount} sandpit permits — adjust capability or availability.`}</p><p>After the sandpit plan, <b>${permit.suggestedQuarryOnlyCount}</b> of ${permit.workingTruckCount} working truck(s) can be Quarry Only. You marked <b>${permit.markedQuarryOnly}</b> Quarry Only today.</p>${quarryRotation ? `<p>Fair quarry rotation suggestion: <b>${esc(quarryRotation)}</b>.</p>` : ""}</section>${permitWarnings.length ? `<section class="alert"><b>Permit plan note</b>${permitWarnings.map((item) => `<p>${esc(item)}</p>`).join("")}</section>` : ""}<section class="panel compact-panel"><div class="table-scroll"><table class="compact-table capacity-table"><thead><tr><th>Trip type</th><th>Customer need</th><th>Possible maximum</th><th>Balance</th></tr></thead><tbody>${rows.map((row) => `<tr class="${row.capacity - row.need < 0 ? "mismatch" : "ok"}"><td>${row.zone}</td><td>${row.need}</td><td>${row.capacity}</td><td><b>${row.capacity - row.need >= 0 ? "+" : ""}${row.capacity - row.need}</b></td></tr>`).join("")}</tbody></table></div></section>${unresolved.length ? `<section class="alert"><b>Last dispatch could not place ${unresolved.length} load(s)</b>${unresolved.map((item) => `<p>${esc(customer(item.customerId)?.name || "Permit plan")} — ${esc(item.reason)}</p>`).join("")}</section>` : ""}<button class="primary wide" data-action="run-dispatch">Auto-generate dispatch</button><p class="workflow-next">Far and Stone loads are spread across different suitable trucks first whenever enough capable trucks are available. Own quarry orders are given to Quarry Only trucks first.</p>${activeAssignments().length ? tallyTable() : ""}`; }

function quarryEnquiryPicker() {
  const quarries = state.sources.filter((source) => source.type === "Quarry").sort((left, right) => left.name.localeCompare(right.name));
  const selected = new Set(quarryEnquiriesForDate(state, ui.date).map((source) => source.id));
  if (!quarries.length) return "";
  return `<section class="panel compact-panel quarry-enquiry-panel"><div class="section-head"><div><h2>Quarry enquiries for tomorrow</h2><small>Tick the quarries drivers may ask timbang for. The quarry name and contact will be added below Esok order batu in WhatsApp.</small></div></div><div class="quarry-enquiry-list">${quarries.map((source) => `<label class="quarry-enquiry-row"><input type="checkbox" data-quarry-enquiry-source="${esc(source.id)}" ${selected.has(source.id) ? "checked" : ""}><span><b>${esc(source.name)}</b><small>Timbang: ${esc(source.weighbridgeContact || "contact not set — add it in Settings")}${source.quarryNote ? ` · ${esc(source.quarryNote)}` : ""}</small></span></label>`).join("")}</div></section>`;
}
function financialPanel(finance) {
  const unconfigured = Math.max(0, finance.totalOrderLoads - finance.configuredOrderLoads);
  return `<section class="panel compact-panel finance-panel"><p class="eyebrow">ESTIMATED DAILY MARGIN</p><div class="finance-values"><span><small>Customer margin</small><b>${money(finance.customerMargin)}</b></span><span><small>Sandpit permits</small><b>${finance.permitCount} × ${money(state.settings?.sandpitPermitCost)}</b></span><span><small>Permit cost</small><b>− ${money(finance.permitCost)}</b></span><span><small>After permit cost</small><b class="${finance.netAfterPermit < 0 ? "negative" : ""}">${money(finance.netAfterPermit)}</b></span></div><small>${unconfigured ? `${unconfigured} customer load(s) do not have a margin entered yet, so they contribute RM 0.00 here.` : "Margin uses every current customer order. Add a customer’s margin per load and the permit cost in Settings."}</small></section>`;
}
function tallyPageV8() {
  const capacity = fleetTotals(); const demand = Object.fromEntries(orderTotals().map((item) => [item.zone, item.count])); const dailyBalance = capacity.Daily - activeOrders().reduce((sum, item) => sum + number(item.loads), 0);
  const rows = ["Near", "Far", "Stone"].map((zone) => ({ zone, need: demand[zone], capacity: capacity[zone] })); const unresolved = state.lastAllocation?.date === ui.date ? state.lastAllocation.unresolved || [] : []; const permitWarnings = state.lastAllocation?.date === ui.date ? state.lastAllocation.permitWarnings || [] : [];
  const permit = sandpitPermitPlan(state, ui.date); const finance = financialSummary(state, ui.date); const quarryRotation = permit.recommendedQuarryOnlyTruckIds.map((id) => truckLabel(truck(id))).join(" / "); const farGroups = permit.groups.filter((group) => group.far).length; const nearGroups = permit.groups.filter((group) => !group.far).length;
  const permitMessage = permit.groupCount ? `Full-capacity sandpit plan: ${farGroups ? `${farGroups} × (3 Near + 1 Far)` : ""}${farGroups && nearGroups ? " and " : ""}${nearGroups ? `${nearGroups} × 5 Near` : ""}.` : "No sandpit permit is needed because there are no sandpit orders.";
  const minimumMessage = permit.minimumExtraNearLoads ? `Find at least ${permit.minimumExtraNearLoads} more Near sand load${permit.minimumExtraNearLoads === 1 ? "" : "s"} so every planned permit has the minimum 3 sand loads.` : "Every planned permit can meet the minimum 3 sand loads.";
  const fullMessage = permit.fullCapacityExtraNearLoads ? `For full permit use, find ${permit.fullCapacityExtraNearLoads} more Near sand load${permit.fullCapacityExtraNearLoads === 1 ? "" : "s"} (${permit.nearLoads} now → ${permit.targetNearLoads} full-capacity target).` : "Your current Near sand loads already fill the high-capacity permit plan.";
  return `<section class="page-title"><p class="eyebrow">STEP 3 — CAPACITY CHECK</p><h2>Demand, permits and quarry rotation</h2><p>The allocator follows each truck’s real route combinations. It does not treat a Far trip as an interchangeable fifth Near slot.</p></section><section class="mini-summary ${dailyBalance < 0 ? "warning-summary" : ""}"><span><b>${activeOrders().reduce((sum, item) => sum + number(item.loads), 0)}</b> customer loads</span><span><b>${capacity.Daily}</b> fleet capacity</span><span><b>${dailyBalance >= 0 ? "+" : ""}${dailyBalance}</b> overall balance</span></section><section class="panel compact-panel permit-panel"><p class="eyebrow">SANDPIT PERMIT RECOMMENDATION</p><b>${esc(permitMessage)}</b><p><b>Permit minimum:</b> ${esc(minimumMessage)}</p><p><b>Maximum use:</b> ${esc(fullMessage)}</p><p>${permit.eligibleTruckCount >= permit.groupCount ? `${permit.eligibleTruckCount} truck(s) can cover the ${permit.groupCount} sandpit permit(s).` : `Only ${permit.eligibleTruckCount} suitable truck(s) can cover ${permit.groupCount} sandpit permit(s) — adjust capability or availability.`}</p><p>After the sandpit plan, <b>${permit.suggestedQuarryOnlyCount}</b> of ${permit.workingTruckCount} working truck(s) can be Quarry Only. You marked <b>${permit.markedQuarryOnly}</b> Quarry Only today.</p>${quarryRotation ? `<p>Fair quarry rotation suggestion: <b>${esc(quarryRotation)}</b>.</p>` : ""}</section>${financialPanel(finance)}${quarryEnquiryPicker()}${permitWarnings.length ? `<section class="alert"><b>Permit plan note</b>${permitWarnings.map((item) => `<p>${esc(item)}</p>`).join("")}</section>` : ""}<section class="panel compact-panel"><div class="table-scroll"><table class="compact-table capacity-table"><thead><tr><th>Trip type</th><th>Customer need</th><th>Possible maximum</th><th>Balance</th></tr></thead><tbody>${rows.map((row) => `<tr class="${row.capacity - row.need < 0 ? "mismatch" : "ok"}"><td>${row.zone}</td><td>${row.need}</td><td>${row.capacity}</td><td><b>${row.capacity - row.need >= 0 ? "+" : ""}${row.capacity - row.need}</b></td></tr>`).join("")}</tbody></table></div></section>${unresolved.length ? `<section class="alert"><b>Last dispatch could not place ${unresolved.length} load(s)</b>${unresolved.map((item) => `<p>${esc(customer(item.customerId)?.name || "Permit plan")} — ${esc(item.reason)}</p>`).join("")}</section>` : ""}<button class="primary wide" data-action="run-dispatch">Auto-generate dispatch</button><p class="workflow-next">Far and Stone loads are spread across different suitable trucks first whenever possible. Own quarry orders go to Quarry Only trucks first.</p>${activeAssignments().length ? tallyTable() : ""}`;
}
function quarryLogCell(item, trips) { if (trips.length || !isDispatchable(item)) return "<td class='grid-empty'>—</td>"; const log = (state.quarryTripLogs || []).find((entry) => entry.date === ui.date && entry.truckId === item.id); const open = log || ui.openQuarryLogTruck === item.id; if (!open) return `<td class="quarry-log-cell quarry-log-add"><b>No company order</b><button class="tiny-add" data-action="add-quarry-log" data-truck="${esc(item.id)}">+ Add quarry order</button></td>`; return `<td class="quarry-log-cell" data-quarry-truck="${esc(item.id)}"><b>Quarry order done</b><label>Loads<input type="number" min="0" inputmode="numeric" data-quarry-field="loads" value="${esc(number(log?.loads))}"></label><input data-quarry-field="remark" value="${esc(log?.remark || "")}" placeholder="Which quarry / order note"></td>`; }
function gridRows(type) { const columns = tripColumns(); return state.trucks.filter((item) => !["off", "breakdown"].includes(String(item.status).toLowerCase())).map((item) => { const trips = activeAssignments().filter((assignment) => assignment.truckId === item.id).sort((a, b) => a.tripNumber - b.tripNumber); return `<tr data-truck="${esc(item.id)}" data-status="${esc(item.status.toLowerCase())}"><td class="sticky-col grid-truck"><b class="truck-name">${esc(truckLabel(item))}</b>${badge(item.status)}<small>${trips.length}/${maximumTruckTrips(item)} own orders</small>${type === "dispatch" ? `<button class="tiny-add" data-action="add-manual-trip" data-truck="${esc(item.id)}">+ trip</button>` : ""}</td>${Array.from({ length: columns }, (_, index) => type === "dispatch" ? dispatchCell(trips[index]) : logCell(trips[index])).join("")}${type === "log" ? quarryLogCell(item, trips) : ""}</tr>`; }).join(""); }
function dispatchCell(assignment) { if (!assignment) return "<td class='grid-empty'>—</td>"; return `<td class="dispatch-grid-cell" data-assignment="${esc(assignment.id)}"><select data-assignment-field="customerId">${customerOptions(assignment.customerId)}</select><div><select data-assignment-field="zone">${zoneOptions(assignment.zone)}</select><span class="early-mark ${assignment.early ? "show" : ""}">Early</span><button class="delete" data-action="remove-trip" data-id="${esc(assignment.id)}">×</button></div></td>`; }
function dispatchPage() { const columns = tripColumns(); return `<section class="page-title"><p class="eyebrow">STEP 4 — DISPATCH</p><h2>Truck trip board</h2><p>Material and source are taken from the customer order. Off and Breakdown trucks are hidden; the full truck plate is frozen at the left.</p></section>${activeAssignments().length ? `${tallyTable()}<section class="panel compact-panel"><div class="table-scroll grid-scroll"><table class="compact-table dispatch-grid"><thead><tr><th class="sticky-col">Truck</th>${Array.from({ length: columns }, (_, index) => `<th>Trip ${index + 1}</th>`).join("")}</tr></thead><tbody>${gridRows("dispatch")}</tbody></table></div></section><p class="workflow-next">Edits apply automatically. To rebuild the full plan, go back to Tally and auto-generate again.</p>` : `<div class="empty"><b>No dispatch yet.</b><p>Complete Trucks, Orders and Tally first.</p><button class="primary" data-tab="tally">Go to tally</button></div>`}`; }

function logCell(assignment) { if (!assignment) return "<td class='grid-empty'>—</td>"; const log = state.tripLogs.find((item) => item.assignmentId === assignment.id); const status = log?.status || "Planned"; const actual = log?.actualCustomerId || assignment.customerId; return `<td class="log-grid-cell" data-log-assignment="${esc(assignment.id)}" data-log-status="${esc(status)}"><b>${esc(customer(assignment.customerId)?.name || "Unknown customer")}</b><select data-log-field="status"><option ${status === "Planned" ? "selected" : ""}>Planned</option><option ${status === "Completed" ? "selected" : ""}>Completed</option><option ${status === "Changed" ? "selected" : ""}>Changed</option><option ${status === "Skipped" ? "selected" : ""}>Skipped</option></select><select class="actual-customer" data-log-field="actualCustomerId">${customerOptions(actual)}</select><input data-log-field="remark" value="${esc(log?.remark || "")}" placeholder="Remark">${log ? `<button class="tiny-reset" data-action="clear-log" data-id="${esc(assignment.id)}">Reset</button>` : ""}</td>`; }
function logsPage() { const columns = tripColumns(); const visible = state.trucks.some((item) => !["off", "breakdown"].includes(String(item.status).toLowerCase())); return `<section class="page-title"><p class="eyebrow">STEP 6 — ACTUAL TRIPS</p><h2>Trip log board</h2><p>Choose Changed to reveal the actual customer field. If a working truck has no own order, enter its quarry-order loads in the final column.</p></section>${visible ? `<section class="panel compact-panel"><div class="table-scroll grid-scroll"><table class="compact-table log-grid"><thead><tr><th class="sticky-col">Truck</th>${Array.from({ length: columns }, (_, index) => `<th>Trip ${index + 1}</th>`).join("")}<th>Quarry order log</th></tr></thead><tbody>${gridRows("log")}</tbody></table></div></section>` : `<div class="empty"><b>No working truck today.</b><p>Set a truck to Available, Scheduled Repair, or Quarry Only first.</p></div>`}`; }
function whatsappPage() { return `<section class="page-title"><p class="eyebrow">STEP 5 — WHATSAPP</p><h2>Driver message</h2><p>Repeated loads for one truck are grouped as, for example, <b>JYY 5274*2</b>.</p></section>${activeAssignments().length ? `<section class="panel message-card"><pre>${esc(makeWhatsAppMessage(state, ui.date))}</pre><div class="button-row"><button class="primary" data-action="copy-message">Copy message</button><button class="secondary" data-action="open-whatsapp">Open WhatsApp</button></div></section>` : `<div class="empty"><b>No dispatch plan yet.</b><p>Generate the plan first.</p><button class="primary" data-tab="tally">Go to tally</button></div>`}`; }

function sourceEditor(item) { const materials = state.materials.filter((material) => material.sourceId === item.id).sort((a, b) => a.name.localeCompare(b.name)); return `<details class="source-editor" data-source="${esc(item.id)}"><summary><span><b>${esc(item.name)}</b><small>${esc(item.type)} · ${materials.length} material(s)</small></span><span class="material-chips">${materials.map((material) => `<i>${esc(material.name)}</i>`).join("") || "No materials"}</span></summary><div class="detail-body"><div class="inline-form source-fields"><input data-source-field="name" value="${esc(item.name)}"><select data-source-field="type"><option ${item.type === "Sandpit" ? "selected" : ""}>Sandpit</option><option ${item.type === "Quarry" ? "selected" : ""}>Quarry</option></select><input data-source-field="notes" value="${esc(item.notes)}" placeholder="Source note"></div><form class="batch-material-form" data-form="source-material-batch" data-source="${esc(item.id)}"><label>Add materials under this source<textarea required name="materials" placeholder="1x cuci, 2x cuci, Pasir Kasar"></textarea></label><button class="secondary" type="submit">Add materials</button></form><div class="material-edit-list">${materials.map((material) => `<div data-material="${esc(material.id)}"><input data-material-field="name" value="${esc(material.name)}"><select data-material-field="kind"><option ${material.kind === "Sand" ? "selected" : ""}>Sand</option><option ${material.kind === "Stone" ? "selected" : ""}>Stone</option></select><select data-material-field="defaultZone">${zoneOptions(material.defaultZone)}</select><button class="delete" data-action="delete-material" data-id="${esc(material.id)}">Delete</button></div>`).join("") || "<small class='muted'>Add materials above.</small>"}</div></div></details>`; }
function customerRuleEditor(item, rule) { return `<div class="customer-rule" data-rule="${esc(rule.id)}"><select data-rule-field="materialName">${materialNameOptions(rule.materialName, item.kind)}</select><select data-rule-field="sourceMode"><option value="Any" ${rule.sourceMode === "Any" ? "selected" : ""}>Any source</option><option value="Specific" ${rule.sourceMode === "Specific" ? "selected" : ""}>Only selected sources</option></select>${rule.sourceMode === "Specific" ? `<select multiple size="2" data-rule-sources>${sourceMultiOptions(rule.materialName, rule.sourceIds || [])}</select>` : `<span class="any-source-note">Any saved source with this material</span>`}<button class="delete" data-action="remove-customer-rule" data-customer="${esc(item.id)}" data-rule="${esc(rule.id)}">Remove</button></div>`; }
function customerEditor(item) { return `<details class="customer-editor" data-customer="${esc(item.id)}"><summary><span><b>${esc(item.name)}</b><small>${esc(item.kind)} · ${esc(item.defaultZone)} · ${customerAllowedMaterialIds(state, item).length} options</small></span><span>${esc(customerRuleSummary(state, item))}</span></summary><div class="detail-body"><div class="inline-form customer-fields"><input data-customer-field="name" value="${esc(item.name)}"><select data-customer-field="kind"><option ${item.kind === "Sand" ? "selected" : ""}>Sand</option><option ${item.kind === "Stone" ? "selected" : ""}>Stone</option></select><select data-customer-field="defaultZone">${zoneOptions(item.defaultZone)}</select><input data-customer-field="notes" value="${esc(item.notes)}" placeholder="Permanent remark"></div><div class="rule-list">${(item.materialRules || []).map((rule) => customerRuleEditor(item, rule)).join("")}</div><button class="secondary" data-action="add-customer-rule" data-id="${esc(item.id)}">Add material rule</button></div></details>`; }
function settingsPage() { return `<section class="page-title"><p class="eyebrow">SETTINGS</p><h2>Sources, materials and customers</h2><p>Settings are kept separate from the nightly workflow. Changes save automatically.</p></section><section class="panel compact-panel"><div class="section-head"><h2>Company and group reminder</h2></div><input data-setting="companyName" value="${esc(state.companyName)}">${(state.notices || []).map((item, index) => `<div class="notice-row"><input data-notice="${index}" value="${esc(item)}"><button class="delete" data-action="delete-notice" data-id="${index}">Remove</button></div>`).join("")}<button class="secondary" data-action="add-notice">Add group reminder</button></section><details class="panel compact-details"><summary>Add source and materials</summary><form class="source-create-form" data-form="new-source"><div class="inline-form"><input required name="name" placeholder="Sandpit / quarry name"><select name="type"><option>Sandpit</option><option>Quarry</option></select><input name="notes" placeholder="Source note"></div><label>Materials from this source<textarea name="materials" placeholder="1x cuci, 2x cuci, Pasir Kasar"></textarea></label><button class="primary" type="submit">Add source</button></form></details><section class="panel compact-panel"><div class="section-head"><h2>Sources with materials</h2><span>${state.sources.length}</span></div>${state.sources.map(sourceEditor).join("")}</section><details class="panel compact-details"><summary>Add customer</summary><form data-form="new-customer"><div class="inline-form"><input required name="name" placeholder="Customer name"><select name="kind"><option>Sand</option><option>Stone</option></select><select name="defaultZone">${zoneOptions("Near")}</select></div><div class="inline-form"><select required name="materialName">${materialNameOptions()}</select><select name="sourceMode"><option value="Any">Any source</option><option value="Specific">Only selected sources</option></select><select multiple size="2" name="sourceId">${sourceOptions("", false)}</select></div><input name="notes" placeholder="Permanent remark"><button class="primary" type="submit">Add customer</button></form></details><section class="panel compact-panel customer-rules"><div class="section-head"><div><h2>Customer material rules</h2><small>Use Any source for flexible batching/precaster rules; use selected sources for strict requirements.</small></div><span>${state.customers.length}</span></div>${state.customers.map(customerEditor).join("")}</section><section class="panel local-storage-panel"><p class="eyebrow">PHONE DATA</p><h2>Backup and future API</h2><p>Your records stay in this phone’s browser until the later SQLite API is connected.</p><div class="button-row"><button class="primary" data-action="download-backup">Download JSON backup</button><label class="secondary file-button">Restore JSON backup<input id="backup-file" type="file" accept="application/json,.json"></label></div></section>`; }

function sourceEditorV8(item) {
  const materials = state.materials.filter((material) => material.sourceId === item.id).sort((left, right) => left.name.localeCompare(right.name));
  const quarryDetails = item.type === "Quarry" ? `<div class="inline-form quarry-contact-fields"><input data-source-field="weighbridgeContact" value="${esc(item.weighbridgeContact || "")}" placeholder="Timbang contact number"><input data-source-field="quarryNote" value="${esc(item.quarryNote || "")}" placeholder="WhatsApp instruction / note"></div>` : "";
  return `<details class="source-editor" data-source="${esc(item.id)}"><summary><span><b>${esc(item.name)}</b><small>${esc(item.type)} · ${materials.length} material(s)</small></span><span class="material-chips">${materials.map((material) => `<i>${esc(material.name)}</i>`).join("") || "No materials"}</span></summary><div class="detail-body"><div class="inline-form source-fields"><input data-source-field="name" value="${esc(item.name)}"><select data-source-field="type"><option ${item.type === "Sandpit" ? "selected" : ""}>Sandpit</option><option ${item.type === "Quarry" ? "selected" : ""}>Quarry</option></select><input data-source-field="notes" value="${esc(item.notes)}" placeholder="Source note"></div>${quarryDetails}<div class="material-edit-list">${materials.map((material) => `<div data-material="${esc(material.id)}"><input data-material-field="name" value="${esc(material.name)}"><select data-material-field="kind"><option ${material.kind === "Sand" ? "selected" : ""}>Sand</option><option ${material.kind === "Stone" ? "selected" : ""}>Stone</option></select><select data-material-field="defaultZone">${zoneOptions(material.defaultZone)}</select><button class="delete" data-action="delete-material" data-id="${esc(material.id)}">Delete</button></div>`).join("") || "<small class='muted'>No material saved yet.</small>"}</div><form class="batch-material-form" data-form="source-material-batch" data-source="${esc(item.id)}"><label>Add materials under this source<textarea required name="materials" placeholder="1x cuci, 2x cuci, Pasir Kasar"></textarea></label><button class="secondary" type="submit">Add materials</button></form></div></details>`;
}
function customerEditorV8(item) {
  return `<details class="customer-editor" data-customer="${esc(item.id)}"><summary><span><b>${esc(item.name)}</b><small>${esc(item.kind)} · ${esc(item.defaultZone)} · ${customerAllowedMaterialIds(state, item).length} options</small></span><span>${esc(customerRuleSummary(state, item))}</span></summary><div class="detail-body"><div class="inline-form customer-fields"><input data-customer-field="name" value="${esc(item.name)}"><select data-customer-field="kind"><option ${item.kind === "Sand" ? "selected" : ""}>Sand</option><option ${item.kind === "Stone" ? "selected" : ""}>Stone</option></select><select data-customer-field="defaultZone">${zoneOptions(item.defaultZone)}</select><input data-customer-field="marginPerLoad" type="number" min="0" step="0.01" inputmode="decimal" value="${esc(number(item.marginPerLoad))}" placeholder="RM margin / load"><input data-customer-field="notes" value="${esc(item.notes)}" placeholder="Permanent remark"></div><div class="rule-list">${(item.materialRules || []).map((rule) => customerRuleEditor(item, rule)).join("")}</div><button class="secondary" data-action="add-customer-rule" data-id="${esc(item.id)}">Add material rule</button></div></details>`;
}
function settingsPageV8() {
  return `<section class="page-title"><p class="eyebrow">SETTINGS</p><h2>Company, prices, sources and customers</h2><p>These are long-term settings, separate from the nightly workflow. Changes save automatically.</p></section><section class="panel compact-panel"><div class="section-head"><h2>Company and group reminder</h2></div><input data-setting="companyName" value="${esc(state.companyName)}">${(state.notices || []).map((item, index) => `<div class="notice-row"><input data-notice="${index}" value="${esc(item)}"><button class="delete" data-action="delete-notice" data-id="${index}">Remove</button></div>`).join("")}<button class="secondary" data-action="add-notice">Add group reminder</button></section><section class="panel compact-panel finance-settings"><p class="eyebrow">PERMIT AND MARGIN SETTINGS</p><label>Sandpit permit cost — RM per truck per day<input data-setting="sandpitPermitCost" type="number" min="0" step="0.01" inputmode="decimal" value="${esc(number(state.settings?.sandpitPermitCost))}"></label><small>The Tally tab estimates customer margin minus this cost for the required number of sandpit permits. Enter each customer’s margin per load below.</small></section><section class="panel compact-panel"><div class="section-head"><h2>Sources with materials</h2><span>${state.sources.length}</span></div>${state.sources.map(sourceEditorV8).join("")}</section><details class="panel compact-details add-under-list"><summary>Add source and materials</summary><form class="source-create-form" data-form="new-source"><div class="inline-form"><input required name="name" placeholder="Sandpit / quarry name"><select name="type"><option>Sandpit</option><option>Quarry</option></select><input name="notes" placeholder="Source note"></div><div class="inline-form"><input name="weighbridgeContact" placeholder="Timbang contact (for quarry)"><input name="quarryNote" placeholder="Quarry instruction / note"></div><label>Materials from this source<textarea name="materials" placeholder="1x cuci, 2x cuci, Pasir Kasar"></textarea></label><button class="primary" type="submit">Add source</button></form></details><section class="panel compact-panel customer-rules"><div class="section-head"><div><h2>Customer material rules and margin</h2><small>Use Any source for flexible batching/precaster rules; use selected sources for strict requirements.</small></div><span>${state.customers.length}</span></div>${state.customers.map(customerEditorV8).join("")}</section><details class="panel compact-details add-under-list"><summary>Add customer</summary><form data-form="new-customer"><div class="inline-form"><input required name="name" placeholder="Customer name"><select name="kind"><option>Sand</option><option>Stone</option></select><select name="defaultZone">${zoneOptions("Near")}</select><input name="marginPerLoad" type="number" min="0" step="0.01" inputmode="decimal" placeholder="RM margin / load"></div><div class="inline-form"><select required name="materialName">${materialNameOptions()}</select><select name="sourceMode"><option value="Any">Any source</option><option value="Specific">Only selected sources</option></select><select multiple size="2" name="sourceId">${sourceOptions("", false)}</select></div><input name="notes" placeholder="Permanent remark"><button class="primary" type="submit">Add customer</button></form></details><section class="panel local-storage-panel"><p class="eyebrow">PHONE DATA</p><h2>Backup and future API</h2><p>Your records stay in this phone’s browser until the later SQLite API is connected.</p><div class="button-row"><button class="primary" data-action="download-backup">Download JSON backup</button><label class="secondary file-button">Restore JSON backup<input id="backup-file" type="file" accept="application/json,.json"></label></div></section>`;
}
function whatsappPageV8() {
  const enquiries = quarryEnquiriesForDate(state, ui.date);
  return `<section class="page-title"><p class="eyebrow">STEP 5 — WHATSAPP</p><h2>Driver message</h2><p>Repeated loads are grouped, for example <b>JYY 5274*2</b>. ${enquiries.length ? `${enquiries.length} quarry enquiry contact${enquiries.length === 1 ? " is" : "s are"} included.` : "Tick quarry enquiries in Tally when drivers should ask timbang for work."}</p></section><section class="panel message-card"><pre>${esc(makeWhatsAppMessage(state, ui.date))}</pre><div class="button-row"><button class="primary" data-action="copy-message">Copy message</button><button class="secondary" data-action="open-whatsapp">Open WhatsApp</button></div></section>`;
}
function capabilityEditorV9(item) {
  const profiles = item.capabilities || [];
  return `<details class="capability-editor" ${ui.openTruck === item.id ? "open" : ""}><summary><b>Route plans</b><span>${esc(capabilitySummary(item))}</span></summary><p class="field-hint">One line is one complete possible day. Example: 5 Near is the hard maximum; 4 Near or 3 Near + 1 Far is the normal target for a newer truck.</p><div class="capability-list capability-list-v9">${profiles.map((profile) => `<div data-capability="${esc(profile.id)}"><label>Near${stepper("capability", `${item.id}|${profile.id}`, "near", profile.near)}</label><label>Far${stepper("capability", `${item.id}|${profile.id}`, "far", profile.far)}</label><label>Stone${stepper("capability", `${item.id}|${profile.id}`, "stone", profile.stone)}</label><button class="delete" data-action="delete-capability" data-truck="${esc(item.id)}" data-capability="${esc(profile.id)}">Remove plan</button></div>`).join("")}</div><button class="secondary" data-action="add-capability" data-id="${esc(item.id)}">Add route plan</button></details>`;
}
function trucksPageV9() {
  const totals = fleetTotals();
  return `<section class="page-title"><p class="eyebrow">STEP 1 — DAILY FLEET</p><h2>Availability and truck capability</h2><p>Normal loads guide the dispatch first. Maximum loads stay available when tomorrow’s demand is unusually high.</p></section><section class="mini-summary"><span><b>${dispatchableTrucks().length}</b> working trucks</span><span><b>${totals.Daily}</b> hard maximum loads</span><span><b>${totals.Near}/${totals.Far}/${totals.Stone}</b> maximum N / F / S</span></section><section class="panel compact-panel"><div class="section-head"><div><h2>Tomorrow’s fleet</h2><small>Max = hard limit. Normal = comfortable workload used first for fair stone allocation.</small></div></div><div class="table-scroll"><table class="compact-table fleet-table"><thead><tr><th class="sticky-col">Truck</th><th>Route plans and fairness</th></tr></thead><tbody>${state.trucks.map((item) => { const score = loadScore(state, item.id, ui.date); return `<tr data-truck="${esc(item.id)}" data-status="${esc(item.status.toLowerCase())}"><td class="sticky-col truck-cell"><b class="truck-name">${esc(truckLabel(item))}</b><select data-truck-field="status">${statusOptions(item.status)}</select><div class="truck-load-settings"><small><b>Max ${maximumTruckTrips(item)}</b></small><label>Normal loads<input type="number" min="1" max="${maximumTruckTrips(item)}" inputmode="numeric" data-truck-field="comfortableLoads" value="${comfortableTruckTrips(item)}"></label></div><label class="status-reason">Reason<input data-truck-field="statusReason" value="${esc(item.statusReason || "")}" placeholder="Off, breakdown, repair or quarry note"></label></td><td class="fleet-plan-cell">${capabilityEditorV9(item)}${repairEditor(item)}<small class="fairness-line"><b>30-day fairness</b> ${score.historical} loads · ${score.far} Far · ${score.stone} Stone · ${score.quarry} quarry · ${score.planned} planned</small></td></tr>`; }).join("")}</tbody></table></div></section><details class="panel compact-details add-under-list"><summary>Add truck</summary><form class="add-truck-form" data-form="new-truck"><label>Prefix<input name="prefix" placeholder="Example: JSE"></label><label>Full plate number<input required name="number" placeholder="Example: 1349"></label><label>Starting status<select name="status">${statusOptions("Available")}</select></label><label>First plan — Near loads<input name="near" type="number" min="0" value="5"></label><label>First plan — Far loads<input name="far" type="number" min="0" value="0"></label><label>First plan — Stone loads<input name="stone" type="number" min="0" value="0"></label><label>Normal comfortable loads<input name="comfortableLoads" type="number" min="1" value="4"></label><button class="primary" type="submit">Add truck</button></form><small class="muted">Add other valid combinations from the truck’s Route plans afterwards.</small></details>`;
}
function periodPermitEnd(permit) { const end = new Date(`${permit.startDate}T12:00:00`); end.setDate(end.getDate() + Math.max(1, number(permit.durationDays)) - 1); return end.toISOString().slice(0, 10); }
function periodPermitManager() {
  const permits = state.sandpitPermits || []; const activeIds = new Set(activePeriodPermits(state, ui.date).map((item) => item.id));
  return `<section class="panel compact-panel period-permit-panel"><div class="section-head"><div><h2>Period sandpit permits</h2><small>Use this for GSL, GD, or any sandpit where you already paid for several days. Active trucks are guaranteed suitable sand jobs before new daily permits are used.</small></div><span>${activeIds.size} active</span></div><div class="table-scroll"><table class="compact-table period-permit-table"><thead><tr><th>Truck</th><th>Sandpit</th><th>Start</th><th>Days</th><th>RM/day</th><th>Status</th><th></th></tr></thead><tbody>${permits.map((permit) => `<tr data-sandpit-permit="${esc(permit.id)}"><td><select data-sandpit-permit-field="truckId">${truckOptions(permit.truckId)}</select></td><td><select data-sandpit-permit-field="sourceId">${periodSourceOptions(permit.sourceId)}</select></td><td><input data-sandpit-permit-field="startDate" type="date" value="${esc(permit.startDate)}"></td><td><input data-sandpit-permit-field="durationDays" type="number" min="1" inputmode="numeric" value="${esc(number(permit.durationDays))}"></td><td><input data-sandpit-permit-field="pricePerDay" type="number" min="0" step="0.01" inputmode="decimal" value="${esc(number(permit.pricePerDay))}"></td><td>${activeIds.has(permit.id) ? badge("Active") : `<small>Ends ${esc(periodPermitEnd(permit))}</small>`}</td><td><button class="delete" data-action="delete-sandpit-permit" data-id="${esc(permit.id)}">Delete</button></td></tr>`).join("") || "<tr><td colspan='7' class='empty-cell'>No period permit saved.</td></tr>"}</tbody></table></div></section><details class="panel compact-details add-under-list"><summary>Add period sandpit permit</summary><form class="add-period-permit-form" data-form="new-sandpit-permit"><label>Truck<select required name="truckId">${truckOptions()}</select></label><label>Period sandpit<select required name="sourceId">${periodSourceOptions()}</select></label><label>Permit start date<input required name="startDate" type="date" value="${esc(ui.date)}"></label><label>How many days<input required name="durationDays" type="number" min="1" value="7"></label><label>Price per day (RM)<input required name="pricePerDay" type="number" min="0" step="0.01" inputmode="decimal"></label><button class="primary" type="submit">Add period permit</button></form></details>`;
}
function sourceEditorV9(item) {
  const materials = state.materials.filter((material) => material.sourceId === item.id).sort((left, right) => left.name.localeCompare(right.name));
  const quarryDetails = item.type === "Quarry" ? `<div class="inline-form quarry-contact-fields"><input data-source-field="weighbridgeContact" value="${esc(item.weighbridgeContact || "")}" placeholder="Timbang contact number"><input data-source-field="quarryNote" value="${esc(item.quarryNote || "")}" placeholder="WhatsApp instruction / note"></div>` : "";
  const permitDetails = item.type === "Sandpit" ? `<div class="inline-form permit-source-fields"><label>Permit type<select data-source-field="permitScheme"><option ${item.permitScheme === "Daily" ? "selected" : ""}>Daily</option><option ${item.permitScheme === "Period" ? "selected" : ""}>Period</option></select></label><label>Permit price / day (RM)<input data-source-field="permitCostPerDay" type="number" min="0" step="0.01" inputmode="decimal" value="${esc(number(item.permitCostPerDay))}"></label></div><small class="muted">For Period permits, add the truck, start date and number of paid days below this source list.</small>` : "";
  return `<details class="source-editor" data-source="${esc(item.id)}"><summary><span><b>${esc(item.name)}</b><small>${esc(item.type)} · ${materials.length} material(s)</small></span><span class="material-chips">${materials.map((material) => `<i>${esc(material.name)}</i>`).join("") || "No materials"}</span></summary><div class="detail-body"><div class="inline-form source-fields"><input data-source-field="name" value="${esc(item.name)}"><select data-source-field="type"><option ${item.type === "Sandpit" ? "selected" : ""}>Sandpit</option><option ${item.type === "Quarry" ? "selected" : ""}>Quarry</option></select><input data-source-field="notes" value="${esc(item.notes)}" placeholder="Source note"></div>${permitDetails}${quarryDetails}<div class="material-edit-list">${materials.map((material) => `<div data-material="${esc(material.id)}"><input data-material-field="name" value="${esc(material.name)}"><select data-material-field="kind"><option ${material.kind === "Sand" ? "selected" : ""}>Sand</option><option ${material.kind === "Stone" ? "selected" : ""}>Stone</option></select><select data-material-field="defaultZone">${zoneOptions(material.defaultZone)}</select><button class="delete" data-action="delete-material" data-id="${esc(material.id)}">Delete</button></div>`).join("") || "<small class='muted'>No material saved yet.</small>"}</div><form class="batch-material-form" data-form="source-material-batch" data-source="${esc(item.id)}"><label>Add materials under this source<textarea required name="materials" placeholder="1x cuci, 2x cuci, Pasir Kasar"></textarea></label><button class="secondary" type="submit">Add materials</button></form></div></details>`;
}
function financialPanelV9(finance) {
  const unconfigured = Math.max(0, finance.totalOrderLoads - finance.configuredOrderLoads);
  return `<section class="panel compact-panel finance-panel"><p class="eyebrow">ESTIMATED DAILY MARGIN</p><div class="finance-values finance-values-v9"><span><small>Customer margin</small><b>${money(finance.customerMargin)}</b></span><span><small>Daily permits</small><b>${finance.dailyPermitCount} · − ${money(finance.dailyPermitCost)}</b></span><span><small>Period permits today</small><b>${finance.periodPermitCount} · − ${money(finance.periodPermitCost)}</b></span><span><small>After permits</small><b class="${finance.netAfterPermit < 0 ? "negative" : ""}">${money(finance.netAfterPermit)}</b></span></div><small>${unconfigured ? `${unconfigured} customer load(s) do not have a saved margin yet, so they contribute RM 0.00.` : "This estimate includes source-specific daily permits and the daily share of active period permits."}</small></section>`;
}
function tallyPageV9() {
  const capacity = fleetTotals(); const demand = Object.fromEntries(orderTotals().map((item) => [item.zone, item.count])); const dailyBalance = capacity.Daily - activeOrders().reduce((sum, item) => sum + number(item.loads), 0); const rows = ["Near", "Far", "Stone"].map((zone) => ({ zone, need: demand[zone], capacity: capacity[zone] }));
  const unresolved = state.lastAllocation?.date === ui.date ? state.lastAllocation.unresolved || [] : []; const permitWarnings = state.lastAllocation?.date === ui.date ? state.lastAllocation.permitWarnings || [] : []; const permit = sandpitPermitPlan(state, ui.date); const finance = financialSummary(state, ui.date); const quarryRotation = permit.recommendedQuarryOnlyTruckIds.map((id) => truckLabel(truck(id))).join(" / "); const farGroups = permit.groups.filter((group) => group.far).length; const nearGroups = permit.groups.filter((group) => !group.far).length;
  const planText = permit.groupCount ? `Normal daily permit plan: ${farGroups ? `${farGroups} × (3 Near + 1 Far)` : ""}${farGroups && nearGroups ? " and " : ""}${nearGroups ? `${nearGroups} × 4 Near` : ""}.` : "No new daily sandpit permit is needed for the current remaining sand jobs.";
  const periodText = permit.periodPermitCount ? `${permit.periodPermitCount} paid period-permit truck(s) are active. The dispatch reserves ${permit.periodReservedLoads} suitable sand load(s) for them before buying new daily permits.` : "No active period sandpit permit is recorded for this date.";
  const minimumText = permit.minimumExtraNearLoads ? `Find ${permit.minimumExtraNearLoads} more Near sand load${permit.minimumExtraNearLoads === 1 ? "" : "s"} to keep every new daily permit at the 3-sand-load minimum.` : "Every new daily permit can meet the 3-sand-load minimum.";
  const normalText = permit.normalCapacityExtraNearLoads ? `Find ${permit.normalCapacityExtraNearLoads} more Near load${permit.normalCapacityExtraNearLoads === 1 ? "" : "s"} to fill the normal 4-load plan.` : "The remaining daily permits are already at the normal 4-load plan.";
  return `<section class="page-title"><p class="eyebrow">STEP 3 — CAPACITY CHECK</p><h2>Demand, permits and quarry rotation</h2><p>Four loads is the normal workload for newer trucks; three is the normal workload for older trucks. Five is used only when demand needs the hard maximum.</p></section><section class="mini-summary ${dailyBalance < 0 ? "warning-summary" : ""}"><span><b>${activeOrders().reduce((sum, item) => sum + number(item.loads), 0)}</b> customer loads</span><span><b>${capacity.Daily}</b> hard fleet maximum</span><span><b>${dailyBalance >= 0 ? "+" : ""}${dailyBalance}</b> maximum balance</span></section><section class="panel compact-panel permit-panel"><p class="eyebrow">SANDPIT PERMIT RECOMMENDATION</p><b>${esc(planText)}</b><p><b>Paid period permits:</b> ${esc(periodText)}</p><p><b>Daily permit minimum:</b> ${esc(minimumText)}</p><p><b>Normal workload:</b> ${esc(normalText)}</p><p>${permit.eligibleTruckCount >= permit.groupCount ? `${permit.eligibleTruckCount} truck(s) can cover the ${permit.groupCount} new daily permit(s).` : `Only ${permit.eligibleTruckCount} suitable truck(s) can cover ${permit.groupCount} new daily permit(s) — adjust capability or availability.`}</p><p>After sand delivery, <b>${permit.suggestedQuarryOnlyCount}</b> working truck(s) can be Quarry Only. You marked <b>${permit.markedQuarryOnly}</b>.</p>${quarryRotation ? `<p>Fair quarry rotation suggestion: <b>${esc(quarryRotation)}</b>.</p>` : ""}</section>${financialPanelV9(finance)}${quarryEnquiryPicker()}${permitWarnings.length ? `<section class="alert"><b>Permit plan note</b>${permitWarnings.map((item) => `<p>${esc(item)}</p>`).join("")}</section>` : ""}<section class="panel compact-panel"><div class="table-scroll"><table class="compact-table capacity-table"><thead><tr><th>Trip type</th><th>Customer need</th><th>Possible maximum</th><th>Balance</th></tr></thead><tbody>${rows.map((row) => `<tr class="${row.capacity - row.need < 0 ? "mismatch" : "ok"}"><td>${row.zone}</td><td>${row.need}</td><td>${row.capacity}</td><td><b>${row.capacity - row.need >= 0 ? "+" : ""}${row.capacity - row.need}</b></td></tr>`).join("")}</tbody></table></div></section>${unresolved.length ? `<section class="alert"><b>Last dispatch could not place ${unresolved.length} load(s)</b>${unresolved.map((item) => `<p>${esc(customer(item.customerId)?.name || "Permit plan")} — ${esc(item.reason)}</p>`).join("")}</section>` : ""}<button class="primary wide" data-action="run-dispatch">Auto-generate dispatch</button><p class="workflow-next">Own stone orders go to a suitable truck with the lightest normal workload first; the hard maximum is used only if needed.</p>${activeAssignments().length ? tallyTable() : ""}`;
}
function settingsPageV9() {
  return `<section class="page-title"><p class="eyebrow">SETTINGS</p><h2>Company, permits, sources and customers</h2><p>Long-term settings save automatically. Daily truck status and customer loads remain in the main workflow.</p></section><section class="panel compact-panel"><div class="section-head"><h2>Company and group reminder</h2></div><input data-setting="companyName" value="${esc(state.companyName)}">${(state.notices || []).map((item, index) => `<div class="notice-row"><input data-notice="${index}" value="${esc(item)}"><button class="delete" data-action="delete-notice" data-id="${index}">Remove</button></div>`).join("")}<button class="secondary" data-action="add-notice">Add group reminder</button></section><section class="panel compact-panel finance-settings"><p class="eyebrow">FALLBACK PERMIT AND MARGIN SETTINGS</p><label>Fallback daily permit cost — RM<input data-setting="sandpitPermitCost" type="number" min="0" step="0.01" inputmode="decimal" value="${esc(number(state.settings?.sandpitPermitCost))}"></label><small>Set the real permit price for each sandpit in its source row. This fallback is used only when a daily source has no price. Enter customer margin per load below.</small></section><section class="panel compact-panel"><div class="section-head"><h2>Sources with materials and permit price</h2><span>${state.sources.length}</span></div>${state.sources.map(sourceEditorV9).join("")}</section><details class="panel compact-details add-under-list"><summary>Add source and materials</summary><form class="source-create-form" data-form="new-source"><div class="inline-form"><input required name="name" placeholder="Sandpit / quarry name"><select name="type"><option>Sandpit</option><option>Quarry</option></select><input name="notes" placeholder="Source note"></div><div class="inline-form"><input name="weighbridgeContact" placeholder="Timbang contact (for quarry)"><input name="quarryNote" placeholder="Quarry instruction / note"></div><label>Materials from this source<textarea name="materials" placeholder="1x cuci, 2x cuci, Pasir Kasar"></textarea></label><button class="primary" type="submit">Add source</button></form></details>${periodPermitManager()}<section class="panel compact-panel customer-rules"><div class="section-head"><div><h2>Customer material rules and margin</h2><small>Use Any source for flexible batching/precaster rules; use selected sources for strict requirements.</small></div><span>${state.customers.length}</span></div>${state.customers.map(customerEditorV8).join("")}</section><details class="panel compact-details add-under-list"><summary>Add customer</summary><form data-form="new-customer"><div class="inline-form"><input required name="name" placeholder="Customer name"><select name="kind"><option>Sand</option><option>Stone</option></select><select name="defaultZone">${zoneOptions("Near")}</select><input name="marginPerLoad" type="number" min="0" step="0.01" inputmode="decimal" placeholder="RM margin / load"></div><div class="inline-form"><select required name="materialName">${materialNameOptions()}</select><select name="sourceMode"><option value="Any">Any source</option><option value="Specific">Only selected sources</option></select><select multiple size="2" name="sourceId">${sourceOptions("", false)}</select></div><input name="notes" placeholder="Permanent remark"><button class="primary" type="submit">Add customer</button></form></details><section class="panel local-storage-panel"><p class="eyebrow">PHONE DATA</p><h2>Backup and future API</h2><p>Your records stay in this phone’s browser until the later SQLite API is connected.</p><div class="button-row"><button class="primary" data-action="download-backup">Download JSON backup</button><label class="secondary file-button">Restore JSON backup<input id="backup-file" type="file" accept="application/json,.json"></label></div></section>`;
}
function page() { if (ui.tab === "orders") return ordersPage(); if (ui.tab === "tally") return tallyPageV9(); if (ui.tab === "dispatch") return dispatchPage(); if (ui.tab === "whatsapp") return whatsappPageV8(); if (ui.tab === "logs") return logsPage(); if (ui.tab === "settings") return settingsPageV9(); return trucksPageV9(); }
function render() { root.innerHTML = layout(page()); }

function updateTruck(id, field, value) { state = { ...state, trucks: state.trucks.map((item) => item.id === id ? { ...item, [field]: field === "earlyRepair" ? Boolean(value) : field === "comfortableLoads" ? number(value) : value, updatedAt: new Date().toISOString() } : item) }; }
function updateCapability(compositeId, field, value) { const [truckId, profileId] = compositeId.split("|"); state = { ...state, trucks: state.trucks.map((item) => item.id === truckId ? { ...item, capabilities: item.capabilities.map((profile) => profile.id === profileId ? { ...profile, [field]: number(value) } : profile) } : item) }; }
function updateRepair(id, field, value) { state = { ...state, trucks: state.trucks.map((item) => item.id === id ? (field === "repairTime" || field === "earlyRepair" ? { ...item, [field]: field === "earlyRepair" ? Boolean(value) : value } : { ...item, repairCapacity: { ...(item.repairCapacity || {}), [field]: number(value) } }) : item) }; }
function updateOrder(id, field, value) { state = { ...state, orders: state.orders.map((item) => { if (item.id !== id) return item; if (field === "materialId") { const selected = customer(item.customerId); const materialId = value === "__default__" ? defaultCustomerMaterialId(state, selected) : value; return makeOrderFromMaterial({ ...item, materialId, materialOverride: value !== "__default__" }, state); } return { ...item, [field]: field === "loads" ? number(value) : value, updatedAt: new Date().toISOString() }; }) }; }
function updateAssignment(id, field, value) { state = { ...state, assignments: state.assignments.map((item) => { if (item.id !== id) return item; if (field === "customerId") { const selected = customer(value); return makeOrderFromMaterial({ ...item, customerId: value, kind: selected?.kind || item.kind, zone: selected?.defaultZone || item.zone, materialId: defaultCustomerMaterialId(state, selected) || item.materialId }, state); } return { ...item, [field]: value, updatedAt: new Date().toISOString() }; }) }; }
function updateSource(id, field, value) { state = { ...state, sources: state.sources.map((item) => item.id === id ? { ...item, [field]: field === "permitCostPerDay" ? number(value) : value } : item) }; }
function updateMaterial(id, field, value) { state = refreshCustomerMaterialIds({ ...state, materials: state.materials.map((item) => item.id === id ? { ...item, [field]: value } : item) }); }
function updateCustomer(id, field, value) { state = { ...state, customers: state.customers.map((item) => item.id === id ? { ...item, [field]: field === "marginPerLoad" ? number(value) : value } : item) }; }
function updateCustomerRule(customerId, ruleId, field, value) { state = refreshCustomerMaterialIds({ ...state, customers: state.customers.map((item) => item.id === customerId ? { ...item, materialRules: item.materialRules.map((rule) => rule.id === ruleId ? { ...rule, [field]: value } : rule) } : item) }); }
function updateQuarryEnquiry(sourceId, enabled) {
  const current = (state.quarryEnquiries || []).filter((item) => !(item.date === ui.date && item.sourceId === sourceId));
  state = { ...state, quarryEnquiries: enabled ? [...current, { id: uid("quarry-enquiry"), date: ui.date, sourceId, updatedAt: new Date().toISOString() }] : current };
}
function updateSandpitPermit(id, field, value) {
  state = { ...state, sandpitPermits: (state.sandpitPermits || []).map((item) => item.id === id ? { ...item, [field]: ["durationDays", "pricePerDay"].includes(field) ? number(value) : value, updatedAt: new Date().toISOString() } : item) };
}
function parseMaterialNames(value) { const original = String(value || "").split(/[\n,;]+/).map((item) => item.trim()).filter(Boolean); return [...new Map(original.map((item) => [item.toLowerCase(), item])).values()]; }
function addMaterialsToSource(sourceId, names) { const source = sourceById(state, sourceId); if (!source) return 0; const existing = new Set(state.materials.filter((item) => item.sourceId === sourceId).map((item) => item.name.toLowerCase())); const additions = names.filter((name) => !existing.has(name.toLowerCase())).map((name) => ({ id: uid("material"), sourceId, name, kind: source.type === "Quarry" ? "Stone" : "Sand", defaultZone: source.type === "Quarry" ? "Stone" : "Near", notes: "" })); state = refreshCustomerMaterialIds({ ...state, materials: [...state.materials, ...additions] }); return additions.length; }
function clearLog(assignmentId) { state = { ...state, assignments: state.assignments.map((item) => item.id === assignmentId ? { ...item, status: "Planned" } : item), tripLogs: state.tripLogs.filter((item) => item.assignmentId !== assignmentId), makeUps: state.makeUps.filter((item) => item.assignmentId !== assignmentId) }; }
function saveLogCell(cell) { const assignmentId = cell.dataset.logAssignment; const status = cell.querySelector('[data-log-field="status"]').value; if (status === "Planned") { clearLog(assignmentId); autosave("Trip reset"); return; } const actualCustomerId = cell.querySelector('[data-log-field="actualCustomerId"]').value; const remark = cell.querySelector('[data-log-field="remark"]').value; state = recordActualTrip(state, assignmentId, { actualCustomerId, status, remark }); cell.dataset.logStatus = status; autosave("Actual trip saved"); }
function saveQuarryLogCell(cell) { state = recordQuarryTripLog(state, { date: ui.date, truckId: cell.dataset.quarryTruck, loads: cell.querySelector('[data-quarry-field="loads"]').value, remark: cell.querySelector('[data-quarry-field="remark"]').value }); autosave("Quarry order log saved"); }
async function copyMessage() { const text = makeWhatsAppMessage(state, ui.date); try { await navigator.clipboard.writeText(text); showToast("WhatsApp message copied"); } catch { window.prompt("Copy this WhatsApp message:", text); } }
function downloadBackup() { const payload = JSON.stringify({ app: "Dispatch Pilot", schemaVersion: 9, exportedAt: new Date().toISOString(), state }, null, 2); const blob = new Blob([payload], { type: "application/json" }); const link = document.createElement("a"); link.href = URL.createObjectURL(blob); link.download = `dispatch-pilot-backup-${new Date().toISOString().slice(0, 10)}.json`; document.body.appendChild(link); link.click(); link.remove(); URL.revokeObjectURL(link.href); state = { ...state, settings: { ...state.settings, lastBackupAt: new Date().toLocaleString() } }; autosave("JSON backup downloaded"); }
async function restoreBackup(file) { if (!file) return; try { const parsed = JSON.parse(await file.text()); const incoming = parsed.state || parsed; if (!incoming.trucks || !incoming.customers) throw new Error("This is not a Dispatch Pilot backup"); if (!window.confirm("Replace the current phone data with this backup?")) return; state = ensureState(incoming); prepareDate(ui.date); persistAndRender("Backup restored and upgraded"); } catch (error) { showToast(`Backup could not be restored: ${error.message}`, "danger"); } }

root.addEventListener("click", async (event) => {
  const button = event.target.closest("button"); if (!button) return; if (button.dataset.tab) { ui.tab = button.dataset.tab; render(); return; } const action = button.dataset.action;
  if (action === "go-settings") { ui.tab = "settings"; render(); return; }
  if (action === "run-dispatch") { state = applyDispatch(state, ui.date); ui.tab = "dispatch"; persistAndRender("Dispatch generated — edit any special case directly in the grid"); return; }
  if (action === "copy-message") return copyMessage(); if (action === "open-whatsapp") return window.open(`https://wa.me/?text=${encodeURIComponent(makeWhatsAppMessage(state, ui.date))}`, "_blank", "noopener");
  if (action === "add-quarry-log") { ui.openQuarryLogTruck = button.dataset.truck; render(); return; }
  if (action === "step-value") { const input = button.parentElement.querySelector("input"); const next = number(number(input.value) + Number(button.dataset.delta)); if (button.dataset.entity === "order") updateOrder(button.dataset.id, button.dataset.field, next); if (button.dataset.entity === "capability") updateCapability(button.dataset.id, button.dataset.field, next); if (button.dataset.entity === "repair") updateRepair(button.dataset.id, button.dataset.field, next); input.value = next; autosave(); return; }
  if (action === "add-capability") { ui.openTruck = button.dataset.id; state = { ...state, trucks: state.trucks.map((item) => item.id === button.dataset.id ? { ...item, capabilities: [...item.capabilities, { id: uid("cap"), near: 0, far: 0, stone: 0 }] } : item) }; persistAndRender("Capability plan added"); return; }
  if (action === "delete-capability") { const owner = truck(button.dataset.truck); if ((owner?.capabilities || []).length <= 1) return showToast("Keep at least one normal capability plan", "danger"); ui.openTruck = button.dataset.truck; state = { ...state, trucks: state.trucks.map((item) => item.id === button.dataset.truck ? { ...item, capabilities: item.capabilities.filter((profile) => profile.id !== button.dataset.capability) } : item) }; persistAndRender("Capability plan removed"); return; }
  if (action === "delete-order") { state = { ...state, orders: state.orders.filter((item) => item.id !== button.dataset.id) }; persistAndRender("Order line removed"); return; }
  if (action === "remove-trip") { state = { ...state, assignments: state.assignments.filter((item) => item.id !== button.dataset.id) }; persistAndRender("Trip removed — check the tally"); return; }
  if (action === "add-manual-trip") { const target = truck(button.dataset.truck); const selected = String(target?.status).toLowerCase() === "quarry only" ? state.customers.find((item) => item.kind === "Stone") : state.customers[0]; const materialId = defaultCustomerMaterialId(state, selected); if (!target || !materialId) return showToast("Add a customer material rule first", "danger"); const assignment = makeOrderFromMaterial({ id: uid("assignment"), date: ui.date, truckId: target.id, orderId: `manual-${uid("trip")}`, customerId: selected.id, materialId, zone: selected.defaultZone, kind: selected.kind, early: false, notes: "", status: "Planned", tripNumber: 99, createdAt: new Date().toISOString() }, state); state = { ...state, assignments: renumberAssignments([...state.assignments, assignment]) }; persistAndRender("Manual trip added"); return; }
  if (action === "clear-log") { clearLog(button.dataset.id); persistAndRender("Trip reset to planned"); return; }
  if (action === "add-notice") { state = { ...state, notices: [...(state.notices || []), ""] }; persistAndRender("Reminder added"); return; }
  if (action === "delete-notice") { state = { ...state, notices: state.notices.filter((_, index) => String(index) !== button.dataset.id) }; persistAndRender("Reminder removed"); return; }
  if (action === "delete-material") { const used = state.orders.some((item) => item.materialId === button.dataset.id) || state.assignments.some((item) => item.materialId === button.dataset.id); if (used) return showToast("This material is still used by an order or dispatch", "danger"); state = refreshCustomerMaterialIds({ ...state, materials: state.materials.filter((item) => item.id !== button.dataset.id) }); persistAndRender("Material deleted"); return; }
  if (action === "add-customer-rule") { const target = customer(button.dataset.id); const materialName = state.materials.find((item) => item.kind === target?.kind)?.name || ""; state = refreshCustomerMaterialIds({ ...state, customers: state.customers.map((item) => item.id === button.dataset.id ? { ...item, materialRules: [...item.materialRules, { id: uid("rule"), materialName, sourceMode: "Any", sourceIds: [] }] } : item) }); persistAndRender("Material rule added"); return; }
  if (action === "remove-customer-rule") { const target = customer(button.dataset.customer); if ((target?.materialRules || []).length <= 1) return showToast("A customer needs at least one material rule", "danger"); state = refreshCustomerMaterialIds({ ...state, customers: state.customers.map((item) => item.id === button.dataset.customer ? { ...item, materialRules: item.materialRules.filter((rule) => rule.id !== button.dataset.rule) } : item) }); persistAndRender("Material rule removed"); return; }
  if (action === "delete-sandpit-permit") { state = { ...state, sandpitPermits: (state.sandpitPermits || []).filter((item) => item.id !== button.dataset.id) }; persistAndRender("Period permit removed"); return; }
  if (action === "download-backup") return downloadBackup();
});

root.addEventListener("change", (event) => {
  const element = event.target;
  if (element.id === "dispatch-date") { ui.date = element.value; const copied = prepareDate(ui.date); render(); if (copied) flashSave("Previous order copied"); return; }
  if (element.id === "backup-file") { restoreBackup(element.files?.[0]); return; }
  if (element.dataset.newOrderCustomer !== undefined) { ui.newOrderCustomer = element.value; render(); return; }
  if (element.dataset.truckField) { const row = element.closest("[data-truck]"); updateTruck(row.dataset.truck, element.dataset.truckField, element.value); if (element.dataset.truckField === "status") row.dataset.status = element.value.toLowerCase(); autosave(); return; }
  if (element.dataset.repairField) { updateRepair(element.closest("[data-truck]").dataset.truck, element.dataset.repairField, element.type === "checkbox" ? element.checked : element.value); autosave(); return; }
  if (element.dataset.capabilityField) { updateCapability(element.closest("[data-capability]").closest("[data-truck]").dataset.truck + "|" + element.closest("[data-capability]").dataset.capability, element.dataset.capabilityField, element.value); autosave(); return; }
  if (element.dataset.orderField) { updateOrder(element.closest("[data-order]").dataset.order, element.dataset.orderField, element.type === "checkbox" ? element.checked : element.value); autosave(); return; }
  if (element.dataset.assignmentField) { updateAssignment(element.closest("[data-assignment]").dataset.assignment, element.dataset.assignmentField, element.value); autosave(); return; }
  if (element.dataset.logField) { const cell = element.closest("[data-log-assignment]"); if (element.dataset.logField === "status") cell.dataset.logStatus = element.value; saveLogCell(cell); return; }
  if (element.dataset.quarryField) { saveQuarryLogCell(element.closest("[data-quarry-truck]")); return; }
  if (element.dataset.quarryEnquirySource !== undefined) { updateQuarryEnquiry(element.dataset.quarryEnquirySource, element.checked); autosave("Quarry enquiry selection saved"); return; }
  if (element.dataset.sandpitPermitField) { updateSandpitPermit(element.closest("[data-sandpit-permit]").dataset.sandpitPermit, element.dataset.sandpitPermitField, element.value); autosave("Period permit saved"); return; }
  if (element.dataset.sourceField) { updateSource(element.closest("[data-source]").dataset.source, element.dataset.sourceField, element.value); autosave(); return; }
  if (element.dataset.materialField) { updateMaterial(element.closest("[data-material]").dataset.material, element.dataset.materialField, element.value); autosave(); return; }
  if (element.dataset.customerField) { updateCustomer(element.closest("[data-customer]").dataset.customer, element.dataset.customerField, element.value); autosave(); return; }
  if (element.dataset.ruleField) { const editor = element.closest("[data-customer]"); updateCustomerRule(editor.dataset.customer, element.closest("[data-rule]").dataset.rule, element.dataset.ruleField, element.value); autosave(); return; }
  if (element.dataset.ruleSources !== undefined) { const editor = element.closest("[data-customer]"); updateCustomerRule(editor.dataset.customer, element.closest("[data-rule]").dataset.rule, "sourceIds", [...element.selectedOptions].map((option) => option.value)); autosave(); return; }
  if (element.dataset.setting) { state = element.dataset.setting === "sandpitPermitCost" ? { ...state, settings: { ...state.settings, sandpitPermitCost: number(element.value) } } : { ...state, [element.dataset.setting]: element.value }; autosave(); return; }
  if (element.dataset.notice !== undefined) { state = { ...state, notices: state.notices.map((item, index) => String(index) === element.dataset.notice ? element.value : item) }; autosave(); }
});

root.addEventListener("submit", (event) => {
  event.preventDefault(); const form = event.target; const data = new FormData(form); const values = Object.fromEntries(data);
  if (form.dataset.form === "new-truck") { const near = number(values.near); const far = number(values.far); const stone = number(values.stone); const profile = { id: uid("cap"), near, far, stone }; state = { ...state, trucks: [...state.trucks, { id: uid("truck"), prefix: values.prefix?.trim() || "", number: values.number.trim(), status: values.status, statusReason: "", capabilities: [profile], comfortableLoads: number(values.comfortableLoads) || Math.min(4, near + far + stone), repairCapacity: { near: 0, far: 0, stone: 0 }, repairTime: "Morning", earlyRepair: false, notes: "" }] }; persistAndRender("Truck added"); return; }
  if (form.dataset.form === "new-order") { const selected = customer(values.customerId); if (!selected) return showToast("Choose a customer", "danger"); const materialId = values.materialId || defaultCustomerMaterialId(state, selected); if (!materialId) return showToast("This customer needs a valid material rule", "danger"); state = { ...state, orders: [...state.orders, makeOrderFromMaterial({ id: uid("order"), date: ui.date, customerId: selected.id, loads: number(values.loads), zone: values.zone || selected.defaultZone, kind: selected.kind, materialId, materialOverride: Boolean(values.materialId), early: values.early === "on", notes: values.notes || selected.notes || "" }, state)] }; ui.newOrderCustomer = selected.id; persistAndRender("Order line added"); return; }
  if (form.dataset.form === "new-source") { const name = values.name.trim(); const key = name.toLowerCase(); const source = { id: uid("source"), name, type: values.type, notes: values.notes || "", weighbridgeContact: values.weighbridgeContact || "", quarryNote: values.quarryNote || "", permitScheme: values.type === "Sandpit" ? (key.includes("guan") || key.includes("linggiu") ? "Period" : "Daily") : "None", permitCostPerDay: values.type === "Sandpit" && key.includes("ming") ? 130 : 0 }; state = { ...state, sources: [...state.sources, source] }; const added = addMaterialsToSource(source.id, parseMaterialNames(values.materials)); persistAndRender(`Source added${added ? ` with ${added} material(s)` : ""}`); return; }
  if (form.dataset.form === "source-material-batch") { const added = addMaterialsToSource(form.dataset.source, parseMaterialNames(values.materials)); if (!added) return showToast("No new material was added", "danger"); persistAndRender(`${added} material(s) added`); return; }
  if (form.dataset.form === "new-sandpit-permit") { if (!values.truckId || !values.sourceId || !values.startDate) return showToast("Choose truck, sandpit and start date", "danger"); state = { ...state, sandpitPermits: [...(state.sandpitPermits || []), { id: uid("sandpit-permit"), truckId: values.truckId, sourceId: values.sourceId, startDate: values.startDate, durationDays: Math.max(1, number(values.durationDays) || 7), pricePerDay: number(values.pricePerDay), updatedAt: new Date().toISOString() }] }; persistAndRender("Period permit added"); return; }
  if (form.dataset.form === "new-customer") { const rule = { id: uid("rule"), materialName: values.materialName, sourceMode: values.sourceMode === "Specific" ? "Specific" : "Any", sourceIds: data.getAll("sourceId").filter(Boolean) }; const item = { id: uid("customer"), name: values.name.trim(), kind: values.kind, defaultZone: values.defaultZone, materialRules: [rule], marginPerLoad: number(values.marginPerLoad), notes: values.notes || "" }; if (!rule.materialName || !customerAllowedMaterialIds(state, item).length) return showToast("Choose a material and matching source rule", "danger"); state = refreshCustomerMaterialIds({ ...state, customers: [...state.customers, item] }); persistAndRender("Customer added"); }
});

if ("serviceWorker" in navigator) window.addEventListener("load", () => navigator.serviceWorker.register("./sw.js?v=20260716-2", { scope: "./", updateViaCache: "none" }));
